Object.keys(EXTRA_I18N_V4).forEach(k => Object.assign(I18N[k], EXTRA_I18N_V4[k]));

let lang = localStorage.getItem('landing_lang_v4') || localStorage.getItem('landing_lang_v3') || 'zh';
let currentFilter = 'all';
let currentModalView = 'screen';
let currentModalCode = null;
const $ = s => document.querySelector(s);
const $$ = s => [...document.querySelectorAll(s)];
const t = k => (I18N[lang] && I18N[lang][k]) || I18N.zh[k] || k;
const levelLabel = l => l==='S' ? t('beginner') : l==='P' ? t('advanced') : t('high');
const levelOrder = {S:1,P:2,H:3};
const gameText = g => g[lang] || g.zh;
const gameName = g => gameText(g).name;
const gameDesc = g => gameText(g).desc;
function applyTexts(){
  document.documentElement.lang = lang==='zh' ? 'zh-CN' : lang;
  $$('[data-i]').forEach(el => el.textContent = t(el.dataset.i));
  $$('[data-ph]').forEach(el => el.placeholder = t(el.dataset.ph));
  $$('.langBtn').forEach(btn => btn.classList.toggle('active', btn.dataset.lang===lang));
  updatePlanOptions();
  renderGames(currentFilter);
  renderPurchase();
  if (currentModalCode) openModal(currentModalCode, currentModalView);
  generateOrder();
}
function updatePlanOptions(){
  const labels = [t('singlePlan'), t('bundlePlan'), t('allPlan')];
  [...$('#plan').options].forEach((o,i)=>o.textContent = labels[i]);
}
function renderGames(filter='all'){
  currentFilter = filter;
  const list = [...GAMES].sort((a,b)=>(levelOrder[a.level]-levelOrder[b.level]) || a.code.localeCompare(b.code));
  const filtered = filter==='all' ? list : list.filter(g=>g.level===filter);
  $('#gameGrid').innerHTML = filtered.map(g => `
    <article class="gameCard">
      <div class="gameThumb">
        <img src="${g.screen}" alt="${gameName(g)}">
        <span class="codeBadge">${g.code}</span>
        <span class="levelBadge">${levelLabel(g.level)}</span>
      </div>
      <div class="gameBody">
        <h3>${gameName(g)}</h3>
        <p>${gameDesc(g)}</p>
        <div class="gameMeta"><span>${t('modalPrice')} ${t('currency')}${g.price}</span><span>${t('modalFormat')}：${gameText(g).format}</span></div>
        <div class="gameActions">
          <button class="miniBtn" data-action="intro" data-code="${g.code}">${t('modalOpenIntro')}</button>
          <button class="miniBtn primary" data-action="promo" data-code="${g.code}">${t('modalOpenPromo')}</button>
        </div>
      </div>
    </article>`).join('');
  $$('.miniBtn').forEach(btn => btn.onclick = () => openModal(btn.dataset.code, btn.dataset.action === 'promo' ? 'promo' : 'screen'));
  $$('.filter').forEach(f => f.classList.toggle('active', f.dataset.f === filter));
}
function renderPurchase(){
  const list = [...GAMES].sort((a,b)=>(levelOrder[a.level]-levelOrder[b.level]) || a.code.localeCompare(b.code));
  $('#purchaseList').innerHTML = list.map(g => `
    <label class="purchase">
      <input type="checkbox" value="${g.code}">
      <span>${g.code} · ${levelLabel(g.level)} · ${gameName(g)}</span>
      <strong>RM${g.price}</strong>
    </label>`).join('');
}
function openModal(code, view='screen'){
  const g = GAMES.find(x=>x.code===code); if(!g) return;
  currentModalCode = code; currentModalView = view;
  const txt = gameText(g);
  $('#modalBody').innerHTML = `
    <div class="modalContent">
      <div class="modalTop">
        <div class="previewPanel">
          <div class="previewTabs">
            <button class="previewTab ${view==='screen'?'active':''}" data-v="screen">${t('modalScreen')}</button>
            <button class="previewTab ${view==='promo'?'active':''}" data-v="promo">${t('modalPromo')}</button>
          </div>
          <div class="previewFrame">
            <img id="modalPreviewImage" src="${view==='promo' ? g.promo : g.screen}" alt="${gameName(g)}">
            <button class="viewSingle" id="viewSingleBtn">${view==='promo' ? t('modalViewPromo') : t('modalViewScreen')}</button>
          </div>
        </div>
        <div class="infoPanel">
          <div class="titleLine">
            <span class="codeChip">${g.code}</span>
            <span class="levelChip">${levelLabel(g.level)}</span>
          </div>
          <h2>${txt.name}</h2>
          <p>${txt.desc}</p>
          <div class="highlights">${(txt.highlights||[]).map(h=>`<span class="highlight">✨ ${h}</span>`).join('')}</div>
          <div class="detailGrid">
            <div class="detailCard"><h4>${t('modalSubjects')}</h4><p>${txt.subjects}</p></div>
            <div class="detailCard"><h4>${t('modalCore')}</h4><p>${txt.core}</p></div>
            <div class="detailCard"><h4>${t('modalPrep')}</h4><p>${txt.prep}</p></div>
            <div class="detailCard"><h4>${t('modalScenes')}</h4><p>${txt.scenes}</p></div>
          </div>
          <div class="metaRow">
            <div class="formatCard"><h4>${t('modalFormat')}</h4><p>${txt.format}</p></div>
            <div class="formatCard"><h4>${t('modalPrice')}</h4><p>${t('currency')}${g.price}</p></div>
          </div>
          <div class="ctaRow">
            <button class="btn primary modalBuy" data-plan="single">${t('chooseSingle')}</button>
            <button class="btn glass modalViewPromo" data-code="${g.code}">${t('modalOpenPromo')}</button>
          </div>
        </div>
      </div>
    </div>`;
  $('#modal').classList.remove('hidden');
  $$('.previewTab').forEach(tab => tab.onclick = () => openModal(code, tab.dataset.v));
  $('#viewSingleBtn').onclick = ()=>openLightbox(view==='promo' ? g.promo : g.screen);
  $('.modalViewPromo').onclick = ()=>openModal(code, 'promo');
  $('.modalBuy').onclick = () => {
    $('#plan').value = 'single';
    $('#modal').classList.add('hidden');
    location.hash = '#pricing';
    const checkbox = $(`#purchaseList input[value="${code}"]`);
    if (checkbox) checkbox.checked = true;
    generateOrder();
  };
}
function openLightbox(src){ $('#lightboxImg').src = src; $('#lightbox').classList.remove('hidden'); }
function selectedGames(){ return $$('#purchaseList input:checked').map(el => GAMES.find(g=>g.code===el.value)).filter(Boolean); }
function calcTotal(plan, selected){ if(plan==='all') return 300; if(plan==='bundle') return 100; return selected.reduce((sum,g)=>sum+g.price,0); }
function generateOrder(){
  const plan = $('#plan').value;
  const selected = selectedGames();
  const total = calcTotal(plan, selected);
  const gamesText = plan==='all' ? 'ALL / 全站模板' : (selected.length ? selected.map(g=>`${g.code} ${gameName(g)}`).join(', ') : '-');
  const preview = `课堂游戏网站购买申请
${t('orderPlan')}：${$('#plan').selectedOptions[0].textContent}
老师姓名：${$('#buyerName').value || '-'}
学校 / 机构：${$('#buyerSchool').value || '-'}
联系电话：${$('#buyerPhone').value || '-'}
${t('orderGames')}：${gamesText}
${t('orderTotal')}：RM${total}`;
  $('#preview').textContent = preview;
  const wa = $('#whatsappOrder'); if(wa) wa.href = 'https://wa.me/?text=' + encodeURIComponent(preview);
}
function copyOrder(){
  const text = $('#preview').textContent.trim();
  if(!text) return alert(t('noOrder'));
  navigator.clipboard.writeText(text).then(()=>alert(t('copied')));
}
$$('.langBtn').forEach(btn=>btn.onclick=()=>{ lang = btn.dataset.lang; localStorage.setItem('landing_lang_v4', lang); applyTexts(); });
$$('.filter').forEach(btn=>btn.onclick=()=>renderGames(btn.dataset.f));
$$('.plan').forEach(btn=>btn.onclick=()=>{ $('#plan').value = btn.dataset.plan; location.hash = '#pricing'; generateOrder(); });
$('#gen').onclick = generateOrder; $('#copy').onclick = copyOrder;
$('#closeModal').onclick = ()=>{ $('#modal').classList.add('hidden'); currentModalCode = null; };
$('#modal').onclick = (e)=>{ if(e.target.id==='modal'){ $('#modal').classList.add('hidden'); currentModalCode = null; } };
$('#closeLightbox').onclick = ()=>$('#lightbox').classList.add('hidden');
$('#lightbox').onclick = (e)=>{ if(e.target.id==='lightbox') $('#lightbox').classList.add('hidden'); };
['buyerName','buyerSchool','buyerPhone','plan'].forEach(id=>$('#'+id).addEventListener('input', generateOrder));
$('#whatsappOrder')?.addEventListener('click', generateOrder);
applyTexts();


