Object.keys(EXTRA_I18N_V5).forEach(k => Object.assign(I18N[k], EXTRA_I18N_V5[k]));

function sortedGamesV5(){
  return [...GAMES].sort((a,b)=>(levelOrder[a.level]-levelOrder[b.level]) || a.code.localeCompare(b.code));
}
function planLabelV5(plan){
  if(plan === 'single') return t('singlePlan');
  if(plan === 'bundle') return t('bundlePlan');
  return t('allPlan');
}
function selectedGamesV5(){
  if ($('#plan').value === 'all') return sortedGamesV5();
  return $$('#purchaseList input:checked').map(el => GAMES.find(g=>g.code===el.value)).filter(Boolean);
}
function totalV5(){
  const plan = $('#plan').value;
  const selected = selectedGamesV5();
  if(plan === 'all') return 300;
  if(plan === 'bundle') return 100;
  return selected.reduce((sum,g)=>sum+g.price,0);
}
function groupHtmlV5(title, levelClass, games, hint, checkedAll=false, disabled=false){
  return `<div class="purchaseGroup level-${levelClass}">
    <div class="groupTitle"><span>${title}</span><span class="groupHint">${hint || ''}</span></div>
    <div class="groupList">
      ${games.map(g=>`<label class="purchase level-${g.level}">
        <input type="checkbox" value="${g.code}" ${checkedAll?'checked':''} ${disabled?'disabled':''}>
        <span><span class="levelMini">${levelLabel(g.level)}</span> ${g.code} ${gameName(g)}</span>
        <strong>RM${g.price}</strong>
      </label>`).join('')}
    </div>
  </div>`;
}
function renderPurchaseV5(){
  const plan = $('#plan').value;
  const all = sortedGamesV5();
  const s = all.filter(g=>g.level==='S');
  const p = all.filter(g=>g.level==='P');
  const h = all.filter(g=>g.level==='H');
  const sp = all.filter(g=>g.level==='S' || g.level==='P');
  let html = '';
  if(plan === 'single'){
    $('#planGuide').textContent = t('singleGuide');
    html = groupHtmlV5(t('beginnerGroup'), 'S', s, 'RM20') + groupHtmlV5(t('advancedGroup'), 'P', p, 'RM30') + groupHtmlV5(t('highGroup'), 'H', h, 'RM50');
  }else if(plan === 'bundle'){
    $('#planGuide').textContent = t('bundleGuide');
    html = groupHtmlV5(t('beginnerAdvancedGroup'), 'P', sp, t('choose4')) + groupHtmlV5(t('highGroup'), 'H', h, t('choose1'));
  }else{
    $('#planGuide').textContent = t('allGuide');
    html = groupHtmlV5(t('beginnerGroup'), 'S', s, t('includedAll'), true, true) + groupHtmlV5(t('advancedGroup'), 'P', p, t('includedAll'), true, true) + groupHtmlV5(t('highGroup'), 'H', h, t('includedAll'), true, true);
  }
  $('#purchaseList').innerHTML = html;
  $$('#purchaseList input').forEach(cb => cb.addEventListener('change', () => {
    validateSelectionV5(cb);
    updateSummaryV5();
    generateOrderV5();
    hidePaymentV5();
  }));
  updateSummaryV5();
}
function validateSelectionV5(changed){
  const plan = $('#plan').value;
  if(plan !== 'bundle') return;
  const checked = $$('#purchaseList input:checked');
  const sp = checked.filter(cb => {
    const g = GAMES.find(x=>x.code===cb.value);
    return g && (g.level==='S' || g.level==='P');
  });
  const h = checked.filter(cb => {
    const g = GAMES.find(x=>x.code===cb.value);
    return g && g.level==='H';
  });
  const g = GAMES.find(x=>x.code===changed.value);
  if(g && (g.level==='S' || g.level==='P') && sp.length > 4) changed.checked = false;
  if(g && g.level==='H' && h.length > 1) changed.checked = false;
}
function selectionStatusV5(){
  const plan = $('#plan').value;
  const selected = selectedGamesV5();
  if(plan === 'all') return {ok:true, message:t('includedAll')};
  if(plan === 'single'){
    return {ok:selected.length>0, message:selected.length ? `${t('selectedCount')}：${selected.length}` : t('needSingle')};
  }
  const sp = selected.filter(g=>g.level==='S'||g.level==='P').length;
  const h = selected.filter(g=>g.level==='H').length;
  return {ok:sp===4 && h===1, message:`${t('beginnerAdvancedGroup')} ${sp}/4 ｜ ${t('highGroup')} ${h}/1`};
}
function updateSummaryV5(){
  const plan = $('#plan').value;
  const selected = selectedGamesV5();
  const total = totalV5();
  const status = selectionStatusV5();
  $('#payAmount').textContent = `RM${total}`;
  $('#confirmSelection').disabled = !status.ok;
  $('#selectionSummary').innerHTML = `
    <h4>${t('orderConfirmTitle')}</h4>
    <div><b>${t('orderPlan')}：</b>${planLabelV5(plan)}</div>
    <div><b>${t('orderTotal')}：</b>RM${total}</div>
    <div class="${status.ok ? '' : 'warning'}">${status.message}</div>
    <div class="summaryItems">
      ${selected.map(g=>`<div class="summaryItem"><span>${g.code} · ${levelLabel(g.level)} · ${gameName(g)}</span><strong>RM${g.price}</strong></div>`).join('')}
    </div>`;
}
function hidePaymentV5(){
  $('#paymentPanel')?.classList.add('hidden');
}
function showPaymentV5(){
  const status = selectionStatusV5();
  if(!status.ok) return alert(status.message);
  $('#paymentPanel').classList.remove('hidden');
  generateOrderV5();
}
function generateOrderV5(){
  const plan = $('#plan').value;
  const selected = selectedGamesV5();
  const total = totalV5();
  const proof = $('#paymentProof')?.files?.[0]?.name || '-';
  const games = plan === 'all' ? 'ALL / 全站模板' : (selected.map(g=>`${g.code} ${gameName(g)}`).join(', ') || '-');
  const preview = `课堂游戏网站购买申请
${t('orderPlan')}：${planLabelV5(plan)}
老师姓名：${$('#buyerName').value || '-'}
学校 / 机构：${$('#buyerSchool').value || '-'}
联系电话：${$('#buyerPhone').value || '-'}
${t('receiptEmail')}：${$('#buyerEmail').value || '-'}
${t('orderGames')}：${games}
${t('orderTotal')}：RM${total}
${t('paymentProof')}：${proof}
${t('activationNotice')}`;
  $('#preview').textContent = preview;
  const wa = $('#whatsappOrder'); 
  if(wa) wa.href = 'https://wa.me/?text=' + encodeURIComponent(preview);
}
function initPurchaseFlowV5(){
  $('#plan').addEventListener('change', () => {
    renderPurchaseV5();
    generateOrderV5();
    hidePaymentV5();
  });
  ['buyerName','buyerSchool','buyerPhone','buyerEmail'].forEach(id => $('#'+id)?.addEventListener('input', generateOrderV5));
  $('#confirmSelection')?.addEventListener('click', showPaymentV5);
  $('#paymentProof')?.addEventListener('change', () => {
    const file = $('#paymentProof').files[0];
    $('#proofFileName').textContent = file ? file.name : t('noFile');
    generateOrderV5();
  });
  $$('.plan').forEach(btn => {
    btn.onclick = () => {
      $('#plan').value = btn.dataset.plan;
      renderPurchaseV5();
      generateOrderV5();
      hidePaymentV5();
      document.querySelector('#checkoutFlow')?.scrollIntoView({behavior:'smooth', block:'start'});
    };
  });
  renderPurchaseV5();
  generateOrderV5();
}
const oldApplyTextsV5 = applyTexts;
applyTexts = function(){
  oldApplyTextsV5();
  renderPurchaseV5();
  generateOrderV5();
};
initPurchaseFlowV5();
applyTexts();
